  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `employee_id` bigint(20) UNSIGNED NOT NULL,
  `shift_id` bigint(20) UNSIGNED NULL DEFAULT NULL,
  `attendance_date` date NOT NULL,
  `attendance_time` time(0) NOT NULL,
  `attendance_at` datetime(0) NOT NULL,
  `event_type` enum('CHECKIN','CHECKOUT') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `source_type` enum('GPS','DEVICE','MANUAL') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'GPS',
  `location_id` bigint(20) UNSIGNED NULL DEFAULT NULL,
  `latitude` decimal(10, 7) NULL DEFAULT NULL,
  `longitude` decimal(10, 7) NULL DEFAULT NULL,
  `photo_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `notes` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `created_at` datetime(0) NOT NULL DEFAULT current_timestamp(0),
  `updated_at` datetime(0) NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_att_presence_employee_date`(`employee_id`, `attendance_date`) USING BTREE,
  INDEX `idx_att_presence_shift`(`shift_id`) USING BTREE,
  INDEX `idx_att_presence_event_at`(`attendance_at`) USING BTREE,
  INDEX `fk_att_presence_location`(`location_id`) USING BTREE,
  CONSTRAINT `fk_att_presence_employee` FOREIGN KEY (`employee_id`) REFERENCES `org_employee` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_att_presence_location` FOREIGN KEY (`location_id`) REFERENCES `att_location` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_att_presence_shift` FOREIGN KEY (`shift_id`) REFERENCES `att_shift` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 309 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

